from qdrant_client import QdrantClient, models
from fastembed import TextEmbedding, SparseTextEmbedding

# 1. Initialize client and models
client = QdrantClient(url="http://localhost:6333")
dense_model = "sentence-transformers/all-MiniLM-L6-v2"
sparse_model = "Qdrant/bm25"

# 2. Create collection with dense + sparse vectors
client.create_collection(
    collection_name="hybrid_docs",
    vectors_config={
        "dense": models.VectorParams(
            size=384,
            distance=models.Distance.COSINE
        )
    },
    sparse_vectors_config={
        "sparse": models.SparseVectorParams(
            modifier=models.Modifier.IDF
        )
    },
)

# 3. Upsert documents with auto-embedded vectors
documents = ["RAG combines retrieval and generation.", "Hybrid search improves recall."]
client.upsert(
    collection_name="hybrid_docs",
    points=[
        models.PointStruct(
            id=i,
            vector={
                "dense": models.Document(text=doc, model=dense_model),
                "sparse": models.Document(text=doc, model=sparse_model),
            },
            payload={"text": doc}
        )
        for i, doc in enumerate(documents)
    ]
)

# 4. Hybrid search with RRF fusion
results = client.query_points(
    collection_name="hybrid_docs",
    query=models.FusionQuery(fusion=models.Fusion.RRF),
    prefetch=[
        models.Prefetch(
            query=models.Document(text="How does RAG work?", model=dense_model),
            using="dense",
            limit=10,
        ),
        models.Prefetch(
            query=models.Document(text="How does RAG work?", model=sparse_model),
            using="sparse",
            limit=10,
        ),
    ],
    limit=5,
)
